// Build Telegram Bot API reply_markup directly (n8n Telegram node v1.2 cannot evaluate dynamic inlineKeyboard.rows).
const rows = $input.all().map(i => i.json).filter(r => r.id);
const inline_keyboard = rows.map(r => [{
  text: '🎙 ' + (r.agent_name || r.elevenlabs_agent_id),
  callback_data: 'select:' + r.id
}]);
inline_keyboard.push([{ text: '⬅ Назад', callback_data: 'menu' }]);

const text = rows.length
  ? 'Твои агенты — выбери для редактирования:'
  : 'У тебя пока нет агентов. Нажми «Добавить агента».';

const chat_id = $('Parse Update').first().json.chat_id;

return [{ json: { chat_id, text, reply_markup: { inline_keyboard } } }];

